import { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const CreatePost = () => {
  const [title, setTitle] = useState('');
  const [content, setContent] = useState('');
  const { user } = useAuth();

  const handlePost = async (e) => {
    e.preventDefault();
    const token = localStorage.getItem('token');

    try {
      const config = {
        headers: { Authorization: `Bearer ${token}` }
      };

      const newPost = { title, content };
      await axios.post('http://localhost:5000/api/posts', newPost, config);
      
      alert('Post Created!');
      setTitle('');
      setContent('');
    } catch (err) {
      alert(err.response?.data?.message || "Failed to post. Check token.");
    }
  };

  return (
    <div className="create-post-container" style={{ padding: '50px', maxWidth: '600px', margin: '0 auto' }}>
      <h2 style={{ color: '#ff69b4' }}>Create a New Post</h2>
      <form onSubmit={handlePost} style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
        <input 
          type="text" placeholder="Title" value={title}
          onChange={(e) => setTitle(e.target.value)}
          style={{ padding: '10px', borderRadius: '10px', border: '1px solid #ddd' }}
        />
        <textarea 
          placeholder="What's on your mind?" value={content}
          onChange={(e) => setContent(e.target.value)}
          style={{ padding: '10px', borderRadius: '10px', border: '1px solid #ddd', minHeight: '100px' }}
        />
        <button type="submit" style={{ backgroundColor: '#ff69b4', color: 'white', border: 'none', padding: '12px', borderRadius: '20px', cursor: 'pointer' }}>
          Publish Post
        </button>
      </form>
    </div>
  );
};
